#include <stdio.h>
#include <stdbool.h>
#include <string.h>

bool matchesPattern(char* inputString, char* pattern) {
    int m = strlen(inputString), n = strlen(pattern);
    bool dp[m + 1][n + 1];
    dp[0][0] = true;
    for (int j = 1; j <= n; j++) {
        if (pattern[j - 1] == '*') {
            dp[0][j] = dp[0][j - 1];
        }
    }
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (pattern[j - 1] == '*') {
                dp[i][j] = dp[i][j - 1] || dp[i - 1][j];
            } else if (pattern[j - 1] == '?') {
                dp[i][j] = dp[i - 1][j - 1];
            } else {
                dp[i][j] = (inputString[i - 1] == pattern[j - 1]) && dp[i - 1][j - 1];
            }
        }
    }
    return dp[m][n];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char inputString[2001], pattern[2001];
        scanf("%s %s", inputString, pattern);
        printf("%s\n", matchesPattern(inputString, pattern) ? "true" : "false");
    }
    return 0;
}

